// Formater en CSV
const targets = $input.all().map(i => i.json);
const headers = ['id','company_name','sector','contact_name','contact_email','contact_phone','status','priority','score','offer_type','last_contact_date','notes'];
const csv = [headers.join(',')];
targets.forEach(t => {
  const row = headers.map(h => {
    const val = t[h] || '';
    return typeof val === 'string' && val.includes(',') ? `"${val}"` : val;
  });
  csv.push(row.join(','));
});
const csvContent = csv.join('\n');
const timestamp = new Date().toISOString().split('T')[0];
return [{ json: { csv: csvContent, filename: `nexus-targets-${timestamp}.csv`, count: targets.length, timestamp } }];
